/**
* A procedural roller coaster geometry.
*
* @augments BufferGeometry
* @three_import import { RollerCoasterGeometry } from 'three/addons/misc/RollerCoaster.js';
*/
var RollerCoasterGeometry = class extends BufferGeometry {
	/**
	* Constructs a new geometry.
	*
	* @param {Curve} curve - The curve to generate the geometry along.
	* @param {number} divisions - The number of divisions which defines the detail of the geometry.
	*/
	constructor(curve, divisions) {
		super();
		const vertices = [];
		const normals = [];
		const colors = [];
		const color1 = [
			1,
			1,
			1
		];
		const color2 = [
			1,
			1,
			0
		];
		const up = new Vector3(0, 1, 0);
		const forward = new Vector3();
		const right = new Vector3();
		const quaternion = new Quaternion();
		const prevQuaternion = new Quaternion();
		prevQuaternion.setFromAxisAngle(up, Math.PI / 2);
		const point = new Vector3();
		const prevPoint = new Vector3();
		prevPoint.copy(curve.getPointAt(0));
		const step = [
			new Vector3(-.225, 0, 0),
			new Vector3(0, -.05, 0),
			new Vector3(0, -.175, 0),
			new Vector3(0, -.05, 0),
			new Vector3(.225, 0, 0),
			new Vector3(0, -.175, 0)
		];
		const PI2 = Math.PI * 2;
		let sides = 5;
		const tube1 = [];
		for (let i = 0; i < sides; i++) {
			const angle = i / sides * PI2;
			tube1.push(new Vector3(Math.sin(angle) * .06, Math.cos(angle) * .06, 0));
		}
		sides = 6;
		const tube2 = [];
		for (let i = 0; i < sides; i++) {
			const angle = i / sides * PI2;
			tube2.push(new Vector3(Math.sin(angle) * .025, Math.cos(angle) * .025, 0));
		}
		const vector = new Vector3();
		const normal = new Vector3();
		function drawShape(shape, color) {
			normal.set(0, 0, -1).applyQuaternion(quaternion);
			for (let j = 0; j < shape.length; j++) {
				vector.copy(shape[j]);
				vector.applyQuaternion(quaternion);
				vector.add(point);
				vertices.push(vector.x, vector.y, vector.z);
				normals.push(normal.x, normal.y, normal.z);
				colors.push(color[0], color[1], color[2]);
			}
			normal.set(0, 0, 1).applyQuaternion(quaternion);
			for (let j = shape.length - 1; j >= 0; j--) {
				vector.copy(shape[j]);
				vector.applyQuaternion(quaternion);
				vector.add(point);
				vertices.push(vector.x, vector.y, vector.z);
				normals.push(normal.x, normal.y, normal.z);
				colors.push(color[0], color[1], color[2]);
			}
		}
		const vector1 = new Vector3();
		const vector2 = new Vector3();
		const vector3 = new Vector3();
		const vector4 = new Vector3();
		const normal1 = new Vector3();
		const normal2 = new Vector3();
		const normal3 = new Vector3();
		const normal4 = new Vector3();
		function extrudeShape(shape, offset, color) {
			for (let j = 0, jl = shape.length; j < jl; j++) {
				const point1 = shape[j];
				const point2 = shape[(j + 1) % jl];
				vector1.copy(point1).add(offset);
				vector1.applyQuaternion(quaternion);
				vector1.add(point);
				vector2.copy(point2).add(offset);
				vector2.applyQuaternion(quaternion);
				vector2.add(point);
				vector3.copy(point2).add(offset);
				vector3.applyQuaternion(prevQuaternion);
				vector3.add(prevPoint);
				vector4.copy(point1).add(offset);
				vector4.applyQuaternion(prevQuaternion);
				vector4.add(prevPoint);
				vertices.push(vector1.x, vector1.y, vector1.z);
				vertices.push(vector2.x, vector2.y, vector2.z);
				vertices.push(vector4.x, vector4.y, vector4.z);
				vertices.push(vector2.x, vector2.y, vector2.z);
				vertices.push(vector3.x, vector3.y, vector3.z);
				vertices.push(vector4.x, vector4.y, vector4.z);
				normal1.copy(point1);
				normal1.applyQuaternion(quaternion);
				normal1.normalize();
				normal2.copy(point2);
				normal2.applyQuaternion(quaternion);
				normal2.normalize();
				normal3.copy(point2);
				normal3.applyQuaternion(prevQuaternion);
				normal3.normalize();
				normal4.copy(point1);
				normal4.applyQuaternion(prevQuaternion);
				normal4.normalize();
				normals.push(normal1.x, normal1.y, normal1.z);
				normals.push(normal2.x, normal2.y, normal2.z);
				normals.push(normal4.x, normal4.y, normal4.z);
				normals.push(normal2.x, normal2.y, normal2.z);
				normals.push(normal3.x, normal3.y, normal3.z);
				normals.push(normal4.x, normal4.y, normal4.z);
				colors.push(color[0], color[1], color[2]);
				colors.push(color[0], color[1], color[2]);
				colors.push(color[0], color[1], color[2]);
				colors.push(color[0], color[1], color[2]);
				colors.push(color[0], color[1], color[2]);
				colors.push(color[0], color[1], color[2]);
			}
		}
		const offset = new Vector3();
		const sample1 = new Vector3();
		const sample2 = new Vector3();
		const rollQuaternion = new Quaternion();
		for (let i = 1; i <= divisions; i++) {
			point.copy(curve.getPointAt(i / divisions));
			up.set(0, 1, 0);
			forward.subVectors(point, prevPoint).normalize();
			right.crossVectors(up, forward).normalize();
			up.crossVectors(forward, right);
			const angle = Math.atan2(forward.x, forward.z);
			quaternion.setFromAxisAngle(up, angle);
			const bankDelta = .01;
			const t = i / divisions;
			sample1.copy(curve.getTangentAt(((t - bankDelta) % 1 + 1) % 1));
			sample2.copy(curve.getTangentAt((t + bankDelta) % 1));
			let headingChange = Math.atan2(sample2.x, sample2.z) - Math.atan2(sample1.x, sample1.z);
			if (headingChange > Math.PI) headingChange -= Math.PI * 2;
			if (headingChange < -Math.PI) headingChange += Math.PI * 2;
			quaternion.premultiply(rollQuaternion.setFromAxisAngle(forward, -Math.atan(headingChange * 8) * .5));
			if (i % 2 === 0) drawShape(step, color2);
			extrudeShape(tube1, offset.set(0, -.125, 0), color2);
			extrudeShape(tube2, offset.set(.2, 0, 0), color1);
			extrudeShape(tube2, offset.set(-.2, 0, 0), color1);
			prevPoint.copy(point);
			prevQuaternion.copy(quaternion);
		}
		this.setAttribute("position", new BufferAttribute(new Float32Array(vertices), 3));
		this.setAttribute("normal", new BufferAttribute(new Float32Array(normals), 3));
		this.setAttribute("color", new BufferAttribute(new Float32Array(colors), 3));
	}
};
