				normal2.copy(point2);
				normal2.applyQuaternion(quaternion);
				normal2.normalize();
				normal3.copy(point2);
				normal3.applyQuaternion(quaternion);
				normal3.normalize();
				normal4.copy(point1);
				normal4.applyQuaternion(quaternion);
				normal4.normalize();
				normals.push(normal1.x, normal1.y, normal1.z);
				normals.push(normal2.x, normal2.y, normal2.z);
